use actix_files::NamedFile;
use actix_web::{web, App, HttpResponse, HttpServer, Responder};
use std::path::PathBuf;

async fn serve_file(path: web::Path<String>) -> impl Responder {
    let file_path = PathBuf::from("uploads").join(&*path);
    match NamedFile::open(file_path).await {
        Ok(file) => file.into_response(&Default::default()),
        Err(_) => HttpResponse::NotFound().finish(),
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new()
            .route("/uploads/{filename}", web::get().to(serve_file))
    })
    .bind(("127.0.0.1", 8080))?
    .run()
    .await
}